import{_ as e,c as a,o as r,a5 as o}from"./chunks/framework.DwbewbAn.js";const p=JSON.parse('{"title":"MEMORY引擎","description":"","frontmatter":{},"headers":[],"relativePath":"doc/数据库/Mysql/基础/引擎/memory/memory.md","filePath":"packages/doc/src/数据库/Mysql/基础/引擎/memory/memory.md","lastUpdated":1711622925000}'),t={name:"doc/数据库/Mysql/基础/引擎/memory/memory.md"},l=o('<h1 id="memory引擎" tabindex="-1">MEMORY引擎 <a class="header-anchor" href="#memory引擎" aria-label="Permalink to &quot;MEMORY引擎&quot;">​</a></h1><ul><li><a href="https://dev.mysql.com/doc/refman/5.7/en/memory-storage-engine.html" target="_blank" rel="noreferrer">官方链接</a></li></ul><h2 id="memory存储引擎-以前称为-heap-创建具有存储在存储器中的内容的专用的表。由于数据容易受到崩溃、硬件问题或断电的影响-因此只能将这些表用作临时工作区或从其他表中提取的数据的只读缓存。" tabindex="-1"><code>MEMORY</code>存储引擎（以前称为 <code>HEAP</code>）创建具有存储在存储器中的内容的专用的表。由于数据容易受到崩溃、硬件问题或断电的影响，因此只能将这些表用作临时工作区或从其他表中提取的数据的只读缓存。 <a class="header-anchor" href="#memory存储引擎-以前称为-heap-创建具有存储在存储器中的内容的专用的表。由于数据容易受到崩溃、硬件问题或断电的影响-因此只能将这些表用作临时工作区或从其他表中提取的数据的只读缓存。" aria-label="Permalink to &quot;`MEMORY`存储引擎（以前称为 `HEAP`）创建具有存储在存储器中的内容的专用的表。由于数据容易受到崩溃、硬件问题或断电的影响，因此只能将这些表用作临时工作区或从其他表中提取的数据的只读缓存。&quot;">​</a></h2><h2 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h2><h2 id="不支持的特性" tabindex="-1">不支持的特性 <a class="header-anchor" href="#不支持的特性" aria-label="Permalink to &quot;不支持的特性&quot;">​</a></h2><p>MVCC，事务，T树索引，只支持表级别的锁，聚集索引，外键，集群数据库，全文索引，地理空间索引，</p><h2 id="特性-1" tabindex="-1">特性 <a class="header-anchor" href="#特性-1" aria-label="Permalink to &quot;特性&quot;">​</a></h2><p>1.<code>MEMORY</code>表不能包含 <a href="https://dev.mysql.com/doc/refman/5.7/en/blob.html" target="_blank" rel="noreferrer"><code>BLOB</code></a>或 <a href="https://dev.mysql.com/doc/refman/5.7/en/blob.html" target="_blank" rel="noreferrer"><code>TEXT</code></a>列</p><p>2.<code>MEMORY</code>表使用固定长度的行存储格式。诸如<a href="https://dev.mysql.com/doc/refman/5.7/en/char.html" target="_blank" rel="noreferrer"><code>VARCHAR</code></a>使用固定长度存储的变长类型 。</p><h2 id="_5-使用场景" tabindex="-1">5.使用场景 <a class="header-anchor" href="#_5-使用场景" aria-label="Permalink to &quot;5.使用场景&quot;">​</a></h2><ul><li>涉及临时、非关键数据的操作，例如会话管理或缓存。当 MySQL 服务器停机或重启时，<code>MEMORY</code>表中的数据丢失。</li><li>内存存储，可实现快速访问和低延迟。数据量可以完全放在内存中，而不会导致操作系统换出虚拟内存页面。</li><li>只读或以读取为主的数据访问模式（有限更新）。</li></ul>',11),c=[l];function d(m,n,h,s,i,_){return r(),a("div",null,c)}const u=e(t,[["render",d]]);export{p as __pageData,u as default};
